module thermal_sensor_calibration (
    input [7:0] temp_reading, // 8-bit temperature reading
    output [7:0] calibrated_temp // 8-bit calibrated temperature
);
    wire [8:0] temp_with_offset; // 9-bit wire to hold the sum
      wire _n01 = temp_reading[0] ^ 8'd5[0];
  wire _c01 = temp_reading[0] & 8'd5[0];
  wire _n02 = temp_reading[1] ^ 8'd5[1] ^ _c01;
  wire _c02 = (temp_reading[1] & 8'd5[1]) | (temp_reading[1] & _c01) | (8'd5[1] & _c01);
  wire _n03 = temp_reading[2] ^ 8'd5[2] ^ _c02;
  wire _c03 = (temp_reading[2] & 8'd5[2]) | (temp_reading[2] & _c02) | (8'd5[2] & _c02);
  wire _n04 = temp_reading[3] ^ 8'd5[3] ^ _c03;
  wire _c04 = (temp_reading[3] & 8'd5[3]) | (temp_reading[3] & _c03) | (8'd5[3] & _c03);
  assign temp_with_offset = {_n01, _n02, _n03, _n04}; // Add the calibration offset
    assign calibrated_temp = (temp_with_offset > 8'd255) ? 8'd255 : temp_with_offset[7:0]; // Saturate if exceeds 255
endmodule
